package com.example.nofiltercoffee; import android.content.*; import android.os.*; import android.text.*; import android.view.*; import android.widget.*; import androidx.appcompat.app.*; import java.text.*; import java.util.*;
public class CheckoutActivity extends AppCompatActivity{TextView cash,card,total,err,details;LinearLayout form;EditText holder,num,exp,cvv;boolean cardSelected=false,fmtNum=false,fmtExp=false;protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_checkout);cash=findViewById(R.id.btnCashPayment);card=findViewById(R.id.btnCardPayment);total=findViewById(R.id.txtTotal);err=findViewById(R.id.txtCardError);form=findViewById(R.id.cardForm);holder=findViewById(R.id.edtCardHolder);num=findViewById(R.id.edtCardNumber);exp=findViewById(R.id.edtExpiry);cvv=findViewById(R.id.edtCvv);details=findViewById(R.id.txtCustomerDetails);details.setText("Name: "+UserSession.getName(this)+"\nPhone: "+UserSession.getPhone(this)+"\nEmail: "+UserSession.getEmail(this));setupFormatters();findViewById(R.id.btnBack).setOnClickListener(v->finish());cash.setOnClickListener(v->{cardSelected=false;update();});card.setOnClickListener(v->{cardSelected=true;update();});findViewById(R.id.btnConfirm).setOnClickListener(v->confirm());update();}
void setupFormatters(){num.addTextChangedListener(new TextWatcher(){public void beforeTextChanged(CharSequence s,int st,int c,int a){} public void onTextChanged(CharSequence s,int st,int b,int c){} public void afterTextChanged(Editable e){if(fmtNum)return;fmtNum=true;String d=e.toString().replaceAll("\\D","");if(d.length()>16)d=d.substring(0,16);StringBuilder f=new StringBuilder();for(int i=0;i<d.length();i++){if(i>0&&i%4==0)f.append(" ");f.append(d.charAt(i));}num.setText(f.toString());num.setSelection(num.getText().length());fmtNum=false;}});exp.addTextChangedListener(new TextWatcher(){public void beforeTextChanged(CharSequence s,int st,int c,int a){} public void onTextChanged(CharSequence s,int st,int b,int c){} public void afterTextChanged(Editable e){if(fmtExp)return;fmtExp=true;String d=e.toString().replace("/","");if(d.length()>4)d=d.substring(0,4);String out=d.length()>2?d.substring(0,2)+"/"+d.substring(2):d;exp.setText(out);exp.setSelection(exp.getText().length());fmtExp=false;}});} 
void update(){cash.setBackgroundResource(cardSelected?R.drawable.bg_chip_unselected:R.drawable.bg_chip_selected);cash.setTextColor(getResources().getColor(cardSelected?R.color.cream:R.color.espresso_bg));card.setBackgroundResource(cardSelected?R.drawable.bg_chip_selected:R.drawable.bg_chip_unselected);card.setTextColor(getResources().getColor(cardSelected?R.color.espresso_bg:R.color.cream));form.setVisibility(cardSelected?View.VISIBLE:View.GONE);int w=UserSession.getWalletBalance(this),beans=UserSession.getCoffeeBeans(this);int subtotal=CartManager.getSubtotal(),tax=CartManager.getTaxByPayment(cardSelected),promo=CartManager.getPromoDiscount(),wallet=CartManager.getWalletDiscount(w,cardSelected),bd=CartManager.getCoffeeBeansDiscount(beans,w,cardSelected),pay=CartManager.getPayableTotal(w,beans,cardSelected);String s="Subtotal: Rs. "+subtotal+"\n"+(cardSelected?"Tax 5%":"Tax 16%")+": Rs. "+tax; if(CartManager.isPromoRequested()){s+=CartManager.isPromoEligible()?"\nFIRSTORDER voucher: - Rs. "+promo:"\nFIRSTORDER voucher selected: add Rs. "+CartManager.getPromoAmountNeeded()+" more";} if(wallet>0)s+="\nWallet used: - Rs. "+wallet; if(bd>0)s+="\nCoffee Beans used: - "+bd; s+="\nGrand Total: Rs. "+pay+"\n\nCoffee Beans earned: "+CartManager.getCoffeeBeansEarned();total.setText(s);} 
void confirm(){if(cardSelected&&!valid())return;int w=UserSession.getWalletBalance(this),beans=UserSession.getCoffeeBeans(this);int usedW=CartManager.getWalletDiscount(w,cardSelected),usedB=CartManager.getCoffeeBeansDiscount(beans,w,cardSelected),earned=CartManager.getCoffeeBeansEarned(),pay=CartManager.getPayableTotal(w,beans,cardSelected);UserSession.setWalletBalance(this,w-usedW);UserSession.setCoffeeBeans(this,beans-usedB+earned);if(cardSelected)UserSession.saveCard(this,holder.getText().toString().trim(),num.getText().toString().trim(),exp.getText().toString().trim(),cvv.getText().toString().trim());String id="NF-"+(System.currentTimeMillis()%1000000);Calendar cal=Calendar.getInstance();cal.add(Calendar.MINUTE,30);long ms=cal.getTimeInMillis();String time=new SimpleDateFormat("hh:mm a",Locale.getDefault()).format(cal.getTime());UserSession.addOrder(this,id,time,ms,pay);CartManager.clearCart();Intent in=new Intent(this,OrderSuccessActivity.class);in.putExtra("orderId",id);in.putExtra("pickupTime",time);startActivity(in);finish();}
boolean valid(){String n=num.getText().toString().replaceAll("\\s","");if(holder.getText().toString().trim().length()<3)return error("Enter valid card holder name.");if(!n.matches("\\d{16}"))return error("Card number must be exactly 16 digits.");if(!exp.getText().toString().matches("(0[1-9]|1[0-2])/[0-9]{2}"))return error("Expiry must be like 07/27.");if(!cvv.getText().toString().matches("\\d{3}"))return error("CVV must be 3 digits.");err.setVisibility(View.GONE);return true;} boolean error(String s){err.setText(s);err.setVisibility(View.VISIBLE);return false;}}
